564→      case 'invoices':
565→        return <PlaceholderPage title="Facturation" />;
566→      case 'api-keys':
567→      case 'api-developer':
568→        return <ApiDeveloper key={`api-developer-${refreshKey}`} onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
569→      case 'affiliation':
570→        return <Affiliation key={`affiliation-${refreshKey}`} onBack={goBack} user={user} />;
571→      case 'integrations':
572→        return <Integrations key={`integrations-${refreshKey}`} onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
573→      case 'analytics-integrations':
574→        return <AnalyticsIntegrations key={`analytics-integrations-${refreshKey}`} onBack={goBack} user={user} />;
575→      case 'clients':
576→        return <Clients key={`clients-${refreshKey}`} onBack={goBack} onNavigate={(view) => navigateTo(view)} user={user} directClientCount={monthlyProjectCount} maxClients={user ? PLAN_LIMITS[user.plan] : 1} />;
577→      case 'mission-orders':
578→        return <MissionOrders key={`mission-orders-${refreshKey}`} onBack={goBack} user={user} onNavigate={(view) => navigateTo(view)} />;
579→      case 'messages':
