582→        return <PlaceholderPage title="Page introuvable" />;
583→    }
584→  };
585→
586→  // Public pages (no AppShell)
587→  const isPublicPage = ['home', 'login'].includes(currentView);
588→
589→  return (
590→    <ToastContext.Provider value={{ showToast }}>
591→    <div className="min-h-screen font-sans text-gray-100 selection:bg-primary/30">
592→      {/* Toast Notifications */}
593→      <ToastContainer toasts={toasts} onRemove={removeToast} />
594→
595→      {/* First Audit Celebration */}
596→      {showCelebration && (
597→        <div className="fixed inset-0 z-[200] pointer-events-none flex items-center justify-center">
598→          <div className="text-center animate-in fade-in zoom-in duration-500">
599→            <div className="text-6xl mb-4 animate-bounce">🎉</div>
600→            <div className="bg-[#13131d]/90 backdrop-blur-xl border border-purple-500/30 rounded-2xl px-8 py-5 shadow-2xl shadow-purple-900/30">
601→              <h3 className="text-xl font-bold text-white mb-1">Premier audit réussi !</h3>
602→              <p className="text-sm text-purple-300">Votre parcours AEO commence maintenant</p>
603→            </div>
604→          </div>
605→          {Array.from({ length: 20 }).map((_, i) => (
606→            <div
607→              key={i}
608→              className="absolute w-2 h-2 rounded-full"
609→              style={{
610→                background: ['#a855f7', '#8b5cf6', '#f59e0b', '#10b981', '#ec4899'][i % 5],
611→                left: `${20 + Math.random() * 60}%`,
612→                top: `${20 + Math.random() * 60}%`,
