629→      {user && isCommandPaletteOpen && (
630→        <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[20vh]" onClick={() => setIsCommandPaletteOpen(false)}>
631→          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />
632→          <CommandPalettePanel
633→            onClose={() => setIsCommandPaletteOpen(false)}
634→            onNavigate={(view: string) => { navigateTo(view); setIsCommandPaletteOpen(false); }}
635→          />
636→        </div>
637→      )}
638→
639→      {/* Keyboard Shortcuts Modal (?) */}
640→      <ShortcutsModal isOpen={isShortcutsOpen} onClose={() => setIsShortcutsOpen(false)} />
641→
642→      {/* Content */}
643→      {isPublicPage ? (
644→        // Public pages — raw, no AppShell
645→        <div className="bg-black min-h-screen">
646→          {renderPage()}
647→        </div>
648→      ) : (
649→        // Authenticated pages — wrapped in AppShell
650→        <AppShell
651→          activeSection={activeSection}
652→          onSectionChange={handleSectionChange}
653→          activePage={currentView}
654→          onPageChange={handlePageChange}
655→          credits={animatedCredits}
656→          plan={user?.plan || 'free'}
657→          user={user ? { name: user.name, email: user.email } : null}
658→          onOpenCommandPalette={() => setIsCommandPaletteOpen(true)}
659→          onLogoClick={() => navigateTo('dashboard')}
660→        >
661→          {/* Low Credits Warning Banner */}
662→          {user && user.credits <= 10 && !lowCreditsDismissed && currentView !== 'credits' && currentView !== 'recharge' && (
663→            <div className="mb-4 px-4 py-2.5 rounded-xl bg-amber-500/10 border border-amber-500/20 flex items-center gap-3">
664→              <AlertTriangle size={16} className="text-amber-400 shrink-0" />
665→              <p className="text-sm text-amber-300 flex-1">Crédits bientôt épuisés ({user.credits} restants). <button onClick={() => navigateTo('credits')} className="underline font-semibold hover:text-amber-200">Recharger maintenant</button></p>
666→              <button onClick={() => setLowCreditsDismissed(true)} className="text-amber-400/60 hover:text-amber-300"><X size={14} /></button>
667→            </div>
668→          )}
669→
670→          <Suspense fallback={
671→            <div className="space-y-6">
672→              <div className="flex items-center justify-between">
673→                <div className="h-8 w-48 skeleton-shimmer rounded-xl" />
674→                <div className="h-10 w-36 skeleton-shimmer rounded-full" />
675→              </div>
676→              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
677→                {[1,2,3,4].map(i => <div key={i} className="h-28 skeleton-shimmer rounded-2xl border border-white/[0.04]" />)}
678→              </div>
