691→              className="fixed bottom-8 right-6 z-40 w-14 h-14 rounded-full bg-gradient-to-br from-blue-500 to-purple-600 shadow-xl shadow-blue-900/40 flex items-center justify-center text-white hover:scale-110 hover:shadow-2xl transition-all duration-300 group"
692→              title="Nouvel Audit AEO"
693→            >
694→              <Plus size={24} className="group-hover:rotate-90 transition-transform duration-300" />
695→            </button>
696→          )}
697→        </AppShell>
698→      )}
699→    </div>
700→    </ToastContext.Provider>
701→  );
702→};
