 31→    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
 32→    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
 33→    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
